using Microsoft.ML.Data;

namespace TicketClassifier.Models;

public class TicketData
{
    [LoadColumn(0)]
    public string Subject { get; set; } = string.Empty;

    [LoadColumn(1)]
    public string Description { get; set; } = string.Empty;

    [LoadColumn(2)]
    public float Priority { get; set; }

    [LoadColumn(3)]
    public string Category { get; set; } = string.Empty;
}

public class TicketPrediction
{
    [ColumnName("PredictedLabel")]
    public string Category { get; set; } = string.Empty;

    public float[] Score { get; set; } = [];
}

namespace TicketClassifier.Models;

public class TicketRequest
{
    public string Subject { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public int Priority { get; set; } = 3;
}

public class TicketClassificationResult
{
    public string PredictedCategory { get; set; } = string.Empty;
    public Dictionary<string, float> Confidence { get; set; } = new();
}

using Microsoft.ML;
using TicketClassifier.Models;

namespace TicketClassifier.Services;

public class TicketModelTrainer
{
    private readonly MLContext _mlContext = new(seed: 42);
    private readonly ILogger<TicketModelTrainer> _logger;

    public TicketModelTrainer(ILogger<TicketModelTrainer> logger)
    {
        _logger = logger;
    }

    public string TrainAndSave(string dataPath, string modelPath)
    {
        var data = _mlContext.Data.LoadFromTextFile<TicketData>(
            dataPath, hasHeader: true, separatorChar: ',', allowQuoting: true);

        var split = _mlContext.Data.TrainTestSplit(data, testFraction: 0.2, seed: 42);

        var pipeline = _mlContext.Transforms.Text
                .FeaturizeText("SubjectFeatures", nameof(TicketData.Subject))
            .Append(_mlContext.Transforms.Text
                .FeaturizeText("DescriptionFeatures", nameof(TicketData.Description)))
            .Append(_mlContext.Transforms.Concatenate("Features",
                "SubjectFeatures", "DescriptionFeatures", nameof(TicketData.Priority)))
            .Append(_mlContext.Transforms.NormalizeMinMax("Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapValueToKey("Label", nameof(TicketData.Category)))
            .Append(_mlContext.MulticlassClassification.Trainers
                .SdcaMaximumEntropy("Label", "Features"))
            .Append(_mlContext.Transforms.Conversion
                .MapKeyToValue("PredictedLabel"));

        _logger.LogInformation("Training model...");
        var model = pipeline.Fit(split.TrainSet);

        var predictions = model.Transform(split.TestSet);
        var metrics = _mlContext.MulticlassClassification.Evaluate(predictions);

        var report = FormatMetrics(metrics);
        _logger.LogInformation("Model evaluation:\n{Report}", report);

        _mlContext.Model.Save(model, split.TrainSet.Schema, modelPath);
        _logger.LogInformation("Model saved to {Path}", modelPath);

        return report;
    }

    private static string FormatMetrics(
        Microsoft.ML.Data.MulticlassClassificationMetrics metrics)
    {
        return $"""
            ╔════════════════════════════════════════╗
            ║      Model Evaluation Metrics          ║
            ╠════════════════════════════════════════╣
            ║  Macro Accuracy:   {metrics.MacroAccuracy,18:P2} ║
            ║  Micro Accuracy:   {metrics.MicroAccuracy,18:P2} ║
            ║  Log Loss:         {metrics.LogLoss,18:F4} ║
            ║  Log Loss Reductn: {metrics.LogLossReduction,18:F4} ║
            ╚════════════════════════════════════════╝
            Confusion Matrix:
            {metrics.ConfusionMatrix.GetFormattedConfusionTable()}
            """;
    }
}

using Microsoft.AspNetCore.Mvc;
using Microsoft.Extensions.ML;
using TicketClassifier.Models;
using TicketClassifier.Services;

namespace TicketClassifier.Controllers;

[ApiController]
[Route("api/[controller]")]
public class TicketClassifierController : ControllerBase
{
    private readonly PredictionEnginePool<TicketData, TicketPrediction> _predictionPool;
    private readonly TicketModelTrainer _trainer;
    private readonly ILogger<TicketClassifierController> _logger;
    private static readonly string[] Categories = ["Billing", "General", "Technical"];

    public TicketClassifierController(
        PredictionEnginePool<TicketData, TicketPrediction> predictionPool,
        TicketModelTrainer trainer,
        ILogger<TicketClassifierController> logger)
    {
        _predictionPool = predictionPool;
        _trainer = trainer;
        _logger = logger;
    }

    [HttpPost("predict")]
    public ActionResult<TicketClassificationResult> Predict([FromBody] TicketRequest request)
    {
        if (string.IsNullOrWhiteSpace(request.Subject) && string.IsNullOrWhiteSpace(request.Description))
            return BadRequest("Subject or Description is required.");

        if (request.Priority is < 1 or > 3)
            return BadRequest("Priority must be between 1 and 3.");

        var input = new TicketData
        {
            Subject = request.Subject,
            Description = request.Description,
            Priority = request.Priority
        };

        var prediction = _predictionPool.Predict(input);

        var confidence = new Dictionary<string, float>();
        for (int i = 0; i < prediction.Score.Length && i < Categories.Length; i++)
            confidence[Categories[i]] = prediction.Score[i];

        _logger.LogInformation("Predicted {Category} for \"{Subject}\"",
            prediction.Category, request.Subject);

        return Ok(new TicketClassificationResult
        {
            PredictedCategory = prediction.Category,
            Confidence = confidence
        });
    }

    [HttpPost("train")]
    public ActionResult<string> Train()
    {
        var dataPath = Path.Combine(AppContext.BaseDirectory, "Data", "tickets.csv");
        var modelPath = Path.Combine(AppContext.BaseDirectory, "Data", "ticket_model.zip");

        if (!System.IO.File.Exists(dataPath))
            return NotFound("Training data not found.");

        var report = _trainer.TrainAndSave(dataPath, modelPath);
        return Ok(report);
    }
}

